SELECT COALESCE(operator_name, '未记录') AS "operatorName", COUNT(*) AS "operationCount", SUM(CASE WHEN type = '发放' THEN 1 ELSE 0 END) AS "dispenseCount", SUM(CASE WHEN type = '入库' THEN 1 ELSE 0 END) AS "inboundCount" FROM pharmacy_transaction
transaction_time >= #{startDate} AND transaction_time <= #{endDate}
GROUP BY operator_name ORDER BY "operationCount" DESC
